var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 10월 1일 런던, 미스캐토닉 대학","JPN":"1888年10月1日　ロンドン、ミスカトニック大学","ENG":"October 1, 1888, London, Miskatonic University","TWN":"1888年10月1日 倫敦，密斯卡托尼克大學","SCN":"1888年10月1日 伦敦，密斯卡托尼克大学","DEU":"October 1, 1888, London, Miskatonic University","FRA":"October 1, 1888, London, Miskatonic University"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"오늘 자 신문입니다.","JPN":"今日の新聞です。","ENG":"This is today's newspaper.","TWN":"今天的報紙……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"아무래도 간밤에 복수귀가 제물을 하나 더 처리해 버린 모양이군요.","JPN":"どうやら昨夜、復讐鬼がもう一人の生贄を殺害したようです。","ENG":"It seems that the Revenger disposed of another offering last night.","TWN":"看來昨晚復仇鬼又處理了一個祭品。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"경찰력이 총동원된 거리에서 한 시간 사이에 둘이나 죽이다니, 실력이 대단합니다.","JPN":"警察が総動員している街で一時間の間にニ人も殺すとは、素晴らしい実力です。","ENG":"Killing two in an hour on a street filled with police. It's unbelievable.","TWN":"在警力全部出動的街道上，一個小時內殺了兩個人，真是了不起的本事。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"마그눔 오푸스. 그야, 심야의 살인마는 내 최후의 걸작이니까.","JPN":"マグヌム・オプス。当たり前だ、深夜の殺人鬼こそ私の最後の傑作だから。","ENG":"Magnum Opus. That is because the Midnight Killer is my final masterpiece.","TWN":"偉大傑作在上。那是因為，午夜殺人魔是我最後的傑作。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그녀의 일은 신경 쓸 것 없네. 문제가 있다면 그 남자겠지.","JPN":"彼女のことなら気にする必要はない。問題があるとしたらあの男だろう。","ENG":"Don't worry about her. If there is anything to be concerned about, it should be that man.","TWN":"不用操心她。如果有問題，那肯定是那個男人。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 남자라 하시면 역시…….","JPN":"あの男と言いますと、やはり……","ENG":"By that man, you mean...","TWN":"你說的那個男人是……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"오랜만일세. 숙적.","JPN":"久々だな。我が宿敵。","ENG":"Long time no see, my nemesis.","TWN":"好久不見，我的宿敵。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 이상하군. 자네가 왜 런던에 있지? 분명, 프랑스에 있어야 할 텐데 말이야.","JPN":"だが妙だな。どうして君がロンドンにいる？　確か、フランスにいるはずだろうが。","ENG":"How strange seeing you in London. I heard you were supposed to be in France.","TWN":"但是我很疑惑，你為什麼會在倫敦？你明明應該去了法國啊？"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그럼 그렇지.","JPN":"ふふ、そういうことか。","ENG":"Haha. Of, course.","TWN":"呵呵，這才對嘛。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"역시 이번 사건에도 관여하고 있었나?","JPN":"やはりこの事件にも関わっていたのかね？","ENG":"Are you involved in this case as I expect you are?","TWN":"果然這次事件也有你參與。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내가 왜 신분을 숨기고 런던에 있는 지는, 네 놈이 더 잘 알고 있을 텐데?","JPN":"どうして私が正体を隠してロンドンにいるのかは、貴様もよくわかっているはずだ。","ENG":"I'm sure you know better than I do why I'm in London while hiding my identity.","TWN":"我為什麼要隱藏身份待在倫敦，你應該比我更清楚吧？"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모리어티 교수.","JPN":"モリアーティ教授。","ENG":"Professor Moriarty.","TWN":"莫里蒂教授。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"프랑스에서 발생한 사건도 이곳 못지않은 난제일 텐데…….","JPN":"フランスで発生した事件もここに劣らないほど難解なはずだが……","ENG":"Even the case in France must have been a difficult one to crack like this one...","TWN":"法國發生的案子恐怕也不比這裡小吧……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"설마 웃기지도 않는 가짜 신분까지 만들어가면서 이쪽을 우선시할 줄이야.","JPN":"まさか、偽の身分を作ってまでこちらを優先するとは。","ENG":"Who knew he'd create a ridiculous fake identity and prioritize here.","TWN":"沒想到竟然還編造了一個可笑的假身份，把這邊放在了優先位置。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다는 말은……. 줄곧 찾고 있던 사람을 찾아냈다는 뜻이겠지.","JPN":"ということは……ずっと探していた人を見つけだしたということだろう。","ENG":"That would mean... that he found the person he's been searching for.","TWN":"這麼說……是找到了你一直在找的人吧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"손을 써둘까요?","JPN":"手を打っておきましょうか？","ENG":"Should I take care of him, sir?","TWN":"要我動手嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그렇다고 해도 이제와서 달라질 건 없네.","JPN":"ふふ、だとしても今更何も変わらないよ。","ENG":"Haha, even so, it will change nothing.","TWN":"呵呵，即便如此，現在也不會有什麼改變了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"아무리 뛰어난 재능의 소유자라고 해도, 결국 조직력이 없는 고독한 탐정일 뿐.","JPN":"いくら優れた才能の持ち主だとしても、所詮は組織力を持たぬただの孤独な探偵に過ぎない。","ENG":"No matter how talented he may be, he's still a lonely detective.","TWN":"不管他是多麼出色的天才，最終也不過是個沒有團隊精神的獨狼偵探。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 혼자서는 모든 걸 해결할 수 없어.","JPN":"それに、一人ではすべてを解決することはできないのだ。","ENG":"And he can't solve everything on his own.","TWN":"而且一個人是無法解決所有問題的。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그 남자의 상대는 런던…….","JPN":"あの男の相手はロンドン……","ENG":"That man's opposition is London...","TWN":"那個男人的對手是整個倫敦……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 이 세계에 존재하는 모든 미지일 테니까.","JPN":"いや、この世に存在するすべての未知だから。","ENG":"No, it is all the unknowns that exist in this world.","TWN":"不，應該說是這個世界上所有的未知之物。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};